  snake.unshift(nextHead);
  if (!growPending) snake.pop();

  if (snakeVisual.length !== snake.length) {
    snakeVisual = snake.map((segment, i) => ({
      x: segment.x,
      y: segment.y,
      px: i === 0 ? head.x : snakeVisual[i]?.px ?? segment.x,
      py: i === 0 ? head.y : snakeVisual[i]?.py ?? segment.y
    }));
  }

  for (let i = 0; i < snake.length; i++) {
    const target = snake[i];
    const visual = snakeVisual[i] || (snakeVisual[i] = { x: target.x, y: target.y, px: target.x, py: target.y });
    const prev = i === 0 ? head : snake[i - 1];
    visual.px = visual.px + (target.x - visual.px) * Math.max(0.001, dt);
    visual.py = visual.py + (target.y - visual.py) * Math.max(0.001, dt);
    visual.x = target.x;
    visual.y = target.y;
    visual.prevX = prev.x;
    visual.prevY = prev.y;
