Patching the snake game in the loaded widget now.
_____javascript
const widget = space.chat.transient.get("snake-game");
if (!widget) throw new Error('snake-game widget not found in transient');

const text = typeof widget === 'string' ? widget : (widget.text ?? widget.source ?? widget.content ?? '');
if (!text) throw new Error('snake-game widget source not available');

const replacements = [
  [
    /transition:\s*none\s*;?/g,
    'transition: transform 90ms linear, opacity 90ms linear;'
  ],
  [
    /transform:\s*translate\(([^)]+)\)\s*;?/g,
    'transform: translate($1); transition: transform 90ms linear, opacity 90ms linear;'
  ]
];

let updated = text;
for (const [pattern, replacement] of replacements) updated = updated.replace(pattern, replacement);

if (updated === text) {
  const markers = [
    ['.snake-segment', 'transition: transform 90ms linear, opacity 90ms linear;'],
    ['.segment', 'transition: transform 90ms linear, opacity 90ms linear;']
  ];
  for (const [needle, insert] of markers) {
    const idx = updated.indexOf(needle);
    if (idx !== -1) {
      const brace = updated.indexOf('{', idx);
      if (brace !== -1) {
        const end = updated.indexOf('}', brace);
        if (end !== -1) {
          updated = updated.slice(0, end) + `\n  ${insert}\n` + updated.slice(end);
          break;
        }
      }
    }
  }
}

if (updated === text) throw new Error('No editable motion styles found to patch');

return await space.current.patchWidget('snake-game', { edits: [{ from: text, to: updated }] })

