const findInsertAfter = (needle) => {
  const idx = text.indexOf(needle);
  if (idx === -1) throw new Error(`Missing expected source marker: ${needle}`);
  return idx + needle.length;
};

let out = text;

if (!out.includes("requestAnimationFrame") && !out.includes("transition")) {
  if (!out.includes("const canvas")) {
    throw new Error("Unexpected widget source shape; canvas-based snake game source not found.");
  }

  const styleBlock = `
<style>
  #snake-game-canvas {
    image-rendering: pixelated;
    display: block;
    margin: 0 auto;
    background: #111;
  }
</style>
`;

  if (!out.includes("<style>")) {
    out = styleBlock + "\n" + out;
  }

  const renderPatch = `
const TILE_SIZE = 20;
const MOVE_DURATION = 120;

let animFrame = null;
let lastMoveAt = performance.now();
let prevSnake = null;

function lerp(a, b, t) {
  return a + (b - a) * t;
}

function drawSegment(ctx, x, y, color, radius = 6) {
  const px = x * TILE_SIZE;
  const py = y * TILE_SIZE;
  ctx.fillStyle = color;
  ctx.beginPath();
  ctx.roundRect(px + 1, py + 1, TILE_SIZE - 2, TILE_SIZE - 2, radius);
  ctx.fill();
}

function renderFrame(now) {
  const ctx = canvas.getContext('2d');
  const t = Math.min(1, (now - lastMoveAt) / MOVE_DURATION);
  const eased = t * (2 - t);
  const current = snake;
  const previous = prevSnake || snake;

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = '#111';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  for (let i = 0; i < current.length; i++) {
    const cur = current[i];
    const prev = previous[Math.min(i, previous.length - 1)] || cur;
    const x = lerp(prev.x, cur.x, eased);
    const y = lerp(prev.y, cur.y, eased);
    drawSegment(ctx, x, y, i === 0 ? '#7CFC00' : '#2e8b57');
  }

  if (t < 1) {
    animFrame = requestAnimationFrame(renderFrame);
  } else {
    animFrame = null;
  }
}

function scheduleRender() {
  lastMoveAt = performance.now();
  prevSnake = snake.map(seg => ({ ...seg }));
  if (animFrame) cancelAnimationFrame(animFrame);
  animFrame = requestAnimationFrame(renderFrame);
}
`;

  const insertionPoint = out.indexOf("function draw()");
  if (insertionPoint === -1) throw new Error("Could not locate draw() function for animation patch.");
  out = out.slice(0, insertionPoint) + renderPatch + "\n" + out.slice(insertionPoint);

  out = out.replace(/function moveSnake\(\)\s*\{[\s\S]*?\n\}/, (match) => {
    return match
      .replace(/const head = \{ x: snake\[0\]\.x \+ dx, y: snake\[0\]\.y \+ dy \};/, "const head = { x: snake[0].x + dx, y: snake[0].y + dy };")
      .replace(/snake\.unshift\(head\);\s*snake\.pop\(\);/, "snake.unshift(head);\n  snake.pop();\n  scheduleRender();");
  });

  out = out.replace(/function draw\(\)\s*\{[\s\S]*?\n\}/, (match) => {
    return `
function draw() {
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = '#111';
  ctx.fillRect(0, 0, canvas.width, canvas.height);
  if (!animFrame) {
    scheduleRender();
  }
}
`;
  });
}

return await space.current.patchWidget("snake-game", { edits: [{ type: "replace", content: out }] })

